CREATE TABLE IF NOT EXISTS `ims_amouse_board_card` ( `id` int(11) NOT NULL AUTO_INCREMENT, `weid` int(11) NOT NULL, `openid` varchar(100) NOT NULL, `nickname` varchar(100) NOT NULL, `pcateid` int(10) unsigned NOT NULL DEFAULT '0' COMMENT '分类ID', `headimgurl` varchar(255) NOT NULL, `location_p` varchar(100) NOT NULL DEFAULT '' COMMENT '省', `location_c` varchar(100) NOT NULL DEFAULT '' COMMENT '市', `addr` varchar(500) NOT NULL DEFAULT '' COMMENT '地址', `wechatno` varchar(200) NOT NULL COMMENT '微信号', `qrcode` varchar(250) DEFAULT '' COMMENT '二维码', `intro` varchar(500) DEFAULT '' COMMENT '个人介绍', `hot` int(10) unsigned NOT NULL, `status` tinyint(3) NOT NULL, `top` int(10) unsigned NOT NULL, `createtime` int(10) unsigned NOT NULL DEFAULT '0', `updatetime` int(10) unsigned NOT NULL DEFAULT '0' COMMENT '更新时间', `times` int(11) DEFAULT '0', `follows` int(11) DEFAULT '0', `ticket` varchar(1000) NOT NULL COMMENT 'ticket', `shuaxin` tinyint(2) DEFAULT '0', `listorder` int(10) NOT NULL DEFAULT '0' COMMENT '排序', `svip` int(10) NOT NULL DEFAULT '0' COMMENT 'svip', `uptime` int(11) DEFAULT '0', `mealid` int(10) unsigned NOT NULL COMMENT '套餐ID', `isauto` tinyint(2) DEFAULT '0' COMMENT '自动爆机', `autotime` int(11) DEFAULT '0' COMMENT '自动爆机时间', `vipstatus` tinyint(1) NOT NULL DEFAULT '0', `sviptime` int(11) NOT NULL DEFAULT '0' COMMENT '超级VIP开始时间', `endtime` int(11) DEFAULT '0', `ipcilent` varchar(13) DEFAULT NULL COMMENT 'ip', `qr_img` varchar(500) DEFAULT NULL, `media_id` varchar(500) DEFAULT NULL, `media_time` int(11) DEFAULT '0', `title` varchar(250) NOT NULL, `typeid` int(10) NOT NULL, PRIMARY KEY (`id`), KEY `idx_openid` (`openid`) ) ENGINE=MyISAM AUTO_INCREMENT=36 DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_amouse_board_card_click_log` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT '0', `to_openid` varchar(255) DEFAULT '', `from_openid` varchar(255) DEFAULT '', `clickcredit` int(11) DEFAULT '0', `createtime` int(11) DEFAULT '0', PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`), KEY `idx_openid` (`to_openid`), KEY `idx_createtime` (`createtime`), FULLTEXT KEY `idx_from_openid` (`from_openid`) ) ENGINE=MyISAM AUTO_INCREMENT=3 DEFAULT CHARSET=utf8 COMMENT='分享点击日志设置';
CREATE TABLE IF NOT EXISTS `ims_amouse_board_card_log` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT '0', `openid` varchar(255) DEFAULT '', `cardid` int(11) DEFAULT '0', `from_openid` varchar(255) DEFAULT '', `subcredit` int(11) DEFAULT '0', `ltype` tinyint(1) DEFAULT '0' COMMENT '0默认为空，1为红包任务,2为推广任务', `submoney` decimal(10,2) DEFAULT '0.00', `reccredit` int(11) DEFAULT '0', `recmoney` decimal(10,2) DEFAULT '0.00', `createtime` int(11) DEFAULT '0', `mid` int(10) DEFAULT '0', PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`), KEY `idx_openid` (`openid`), KEY `idx_createtime` (`createtime`), KEY `idx_cardid` (`cardid`), FULLTEXT KEY `idx_from_openid` (`from_openid`) ) ENGINE=MyISAM AUTO_INCREMENT=16 DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_amouse_board_category` ( `id` int(10) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(10) unsigned NOT NULL DEFAULT '0' COMMENT '所属帐号', `name` varchar(50) NOT NULL COMMENT '分类名称', `displayorder` tinyint(3) unsigned NOT NULL DEFAULT '0' COMMENT '排序', `createtime` int(10) unsigned NOT NULL DEFAULT '0', PRIMARY KEY (`id`) ) ENGINE=MyISAM AUTO_INCREMENT=17 DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_amouse_board_clear_log` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT '0', `openid` varchar(255) DEFAULT '', `goodsid` int(11) DEFAULT '0', `read` int(11) NOT NULL DEFAULT '0', `createtime` int(11) DEFAULT '0', `status` tinyint(3) DEFAULT '0' COMMENT '0-未发货 1-已发货 3 取消', `usetime` int(11) DEFAULT '0', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_amouse_board_clear_stock_goods` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT '0', `displayorder` int(11) DEFAULT '0', `title` varchar(255) DEFAULT '', `openid` varchar(255) DEFAULT '', `logo` varchar(255) DEFAULT '', `thumb1` varchar(255) DEFAULT '', `thumb2` varchar(255) DEFAULT '', `thumb3` varchar(255) DEFAULT '', `price` decimal(10,2) DEFAULT '0.00' COMMENT '市场价', `clear_price` decimal(10,2) DEFAULT '0.00' COMMENT '清货价', `viewcount` int(11) DEFAULT '0', `pcateid` int(10) unsigned NOT NULL DEFAULT '0' COMMENT '分类ID', `detail` text, `mobile` varchar(18) DEFAULT NULL COMMENT '卖家联系电话', `status` tinyint(3) DEFAULT '0', `shuaxin` tinyint(2) DEFAULT '0' COMMENT '排序', `listorder` int(10) NOT NULL DEFAULT '0', `createtime` int(11) DEFAULT '0', `endtime` int(11) DEFAULT '0', `uptime` int(11) DEFAULT '0', PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`), KEY `idx_endtime` (`endtime`), KEY `idx_uptime` (`uptime`), KEY `idx_createtime` (`createtime`), KEY `idx_status` (`status`), KEY `idx_displayorder` (`displayorder`), KEY `idx_openid` (`openid`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_amouse_board_clear_sysset` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL, `is_open_clear` tinyint(1) DEFAULT '1' COMMENT '是否开启清货商场', `is_status` tinyint(1) DEFAULT '1' COMMENT '是否开启审核', `outurl` varchar(255) DEFAULT '' COMMENT '任何发布清货商场外链', `refer_credit` int(11) DEFAULT '0' COMMENT '置顶积分', `del_credit` int(11) DEFAULT '0' COMMENT '删除积分', `edit_credit` int(11) DEFAULT '0' COMMENT '编辑积分', `ptotal` int(11) NOT NULL DEFAULT '0' COMMENT '开启条件', PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`) ) ENGINE=MyISAM AUTO_INCREMENT=1 DEFAULT CHARSET=utf8; CREATE TABLE IF NOT EXISTS `ims_amouse_board_creditshop_goods` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT '0', `displayorder` int(11) DEFAULT '0', `title` varchar(255) DEFAULT '', `thumb` varchar(255) DEFAULT '', `price` decimal(10,2) DEFAULT '0.00', `type` tinyint(3) DEFAULT '0', `credit` int(11) DEFAULT '0', `credit2` int(11) DEFAULT '0', `money` decimal(10,2) DEFAULT '0.00', `total` int(11) DEFAULT '0', `totalday` int(11) DEFAULT '0', `detail` text, `status` tinyint(3) DEFAULT '0', `vip` tinyint(3) DEFAULT '0', `istop` tinyint(3) DEFAULT '0', `isrecommand` tinyint(3) DEFAULT '0', `createtime` int(11) DEFAULT '0', `endtime` int(11) DEFAULT '0', PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`), KEY `idx_endtime` (`endtime`), KEY `idx_createtime` (`createtime`), KEY `idx_status` (`status`), KEY `idx_displayorder` (`displayorder`), KEY `idx_istop` (`istop`) ) ENGINE=MyISAM AUTO_INCREMENT=12 DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_amouse_board_creditshop_log` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT '0', `address_phone` varchar(255) DEFAULT '', `address_name` varchar(255) DEFAULT '' COMMENT '收货人', `address` varchar(255) DEFAULT '' COMMENT '收货地址', `openid` varchar(255) DEFAULT '', `goodsid` int(11) DEFAULT '0', `createtime` int(11) DEFAULT '0', `status` tinyint(3) DEFAULT '0' COMMENT '0-未发货 1-已发货 3 取消', `usetime` int(11) DEFAULT '0', `express` varchar(255) DEFAULT '', `expresscom` varchar(255) DEFAULT '', `expresssn` varchar(255) DEFAULT '', PRIMARY KEY (`id`) ) ENGINE=MyISAM AUTO_INCREMENT=32 DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_amouse_board_custom_sysset` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL, `toptxt1` varchar(5) DEFAULT NULL COMMENT '头部文字1', `toplink1` varchar(100) DEFAULT NULL COMMENT '头部链接1', `toptxt2` varchar(5) DEFAULT NULL COMMENT '头部文字1', `toplink2` varchar(100) DEFAULT NULL COMMENT '头部链接2', `toptxt3` varchar(5) DEFAULT NULL COMMENT '头部文字1', `toplink3` varchar(100) DEFAULT NULL COMMENT '头部链接3', `bottomtxt1` varchar(5) DEFAULT '' COMMENT '底部文字1', `bottomlink1` varchar(155) DEFAULT '' COMMENT '底部链接1', `bottomtxt2` varchar(5) DEFAULT '' COMMENT '底部文字2', `bottomlink2` varchar(155) DEFAULT '' COMMENT '底部链接2', `fanstxt` varchar(3) DEFAULT '' COMMENT '加粉文字', `bgimg` varchar(255) DEFAULT '' COMMENT '背景图片', `bgcolor` varchar(10) DEFAULT '' COMMENT '背景颜色', `footcolor` varchar(10) DEFAULT '' COMMENT '底部背景颜色', `credittxt` varchar(5) DEFAULT '' COMMENT '积分文字', `is_open_notice` tinyint(1) DEFAULT '1' COMMENT '是否开启通知', `is_left_open` tinyint(1) DEFAULT '1' COMMENT '是否开启首页左边', `left_thumb` varchar(255) DEFAULT '' COMMENT '左边图片', `leftlink` varchar(255) DEFAULT '' COMMENT '左边图片', `is_right_open` tinyint(1) DEFAULT '1' COMMENT '是否开启首页右边', `right_thumb` varchar(255) DEFAULT '' COMMENT '右边图片', `rightlink` varchar(255) DEFAULT '' COMMENT '右边图片', `noticetxt` varchar(100) DEFAULT '' COMMENT '通知文字', PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC COMMENT='自定义文字链接';
CREATE TABLE IF NOT EXISTS `ims_amouse_board_group_mp` ( `id` int(10) unsigned NOT NULL AUTO_INCREMENT, `weid` int(10) unsigned NOT NULL, `openid` varchar(200) NOT NULL COMMENT '个人名片ID', `title` varchar(100) NOT NULL COMMENT '微信群名称', `qrcode` varchar(250) DEFAULT '' COMMENT '二维码', `mpurl` varchar(500) DEFAULT '' COMMENT '公众号链接', `avater` varchar(250) DEFAULT '' COMMENT '头像', `pcateid` int(10) unsigned NOT NULL DEFAULT '0' COMMENT '分类ID', `hot` int(10) unsigned NOT NULL DEFAULT '0' COMMENT '关注人数', `location_p` varchar(100) NOT NULL DEFAULT '' COMMENT '省', `location_c` varchar(100) NOT NULL DEFAULT '' COMMENT '市', `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1为微信群，2为公众号', `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '审核', `desc` varchar(400) DEFAULT '' COMMENT '描述', `createtime` int(10) unsigned NOT NULL DEFAULT '0', `uptime` int(10) unsigned NOT NULL DEFAULT '0', `shuaxin` tinyint(2) NOT NULL DEFAULT '0' COMMENT '刷新
